CONFIG_HTML = """<!DOCTYPE html><html><head><title>Config</title><style>body{font-family:sans-serif;background:#1e1e1e;color:#fff;text-align:center;margin-top:100px;}.container{background:#2d2d2d;max-width:400px;margin:0 auto;padding:30px;border-radius:8px;}input[type="password"]{padding:12px;margin:15px 0;width:80%;background:#111;color:#fff;border:1px solid #444;border-radius:5px;}input[type="submit"]{padding:12px 24px;background:#5865F2;color:#fff;border:none;border-radius:5px;cursor:pointer;}</style></head><body><div class="container"><h2>🔒 Configurar Senha</h2><p>Defina a senha master para o painel do scn_bot.</p><form method="POST"><input type="password" name="senha" placeholder="Senha admin" required><br><input type="submit" value="Salvar e Entrar"></form></div></body></html>"""

LOGIN_HTML = """<!DOCTYPE html><html><head><title>Login</title><style>body{font-family:sans-serif;background:#1e1e1e;color:#fff;text-align:center;margin-top:100px;}.container{background:#2d2d2d;max-width:400px;margin:0 auto;padding:30px;border-radius:8px;}input[type="password"]{padding:12px;margin:15px 0;width:80%;background:#111;color:#fff;border:1px solid #444;border-radius:5px;}input[type="submit"]{padding:12px 24px;background:#5865F2;color:#fff;border:none;border-radius:5px;cursor:pointer;}</style></head><body><div class="container"><h2>🔑 Login</h2><p>Identifique-se para acessar o painel.</p><form method="POST"><input type="password" name="senha" placeholder="Digite a senha" required><br><input type="submit" value="Entrar"></form></div></body></html>"""

ADMIN_HTML = """<!DOCTYPE html><html><head><title>Dashboard</title><style>body{font-family:sans-serif;background:#131416;color:#e3e5e8;margin:40px;}h1{color:#5865f2;}.grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(200px,1fr));gap:20px;}.card{background:#2f3136;padding:20px;border-radius:8px;border-left:5px solid #5865f2;}.card h3{margin:0;color:#b9bbbe;font-size:12px;text-transform:uppercase;}.card .valor{font-size:24px;font-weight:bold;margin:10px 0;}.status-on{color:#43b581;}.status-off{color:#f04747;}.server-list{list-style:none;padding:0;}.server-list li{padding:8px;background:#202225;margin-bottom:5px;border-radius:4px;border-left:3px solid #43b581;}.logout-btn{display:inline-block;margin-top:20px;padding:10px 20px;background:#f04747;color:#fff;text-decoration:none;border-radius:4px;font-weight:bold;}</style></head><body><h1>⚙️ scn_bot - Painel</h1><div class="grid"><div class="card"><h3>Status</h3><div class="valor {% if bot_online %}status-on{% else %}status-off{% endif %}">{{ 'ONLINE' if bot_online else 'OFFLINE' }}</div></div><div class="card"><h3>Latência</h3><div class="valor">{{ latencia }}</div></div><div class="card"><h3>Servidores</h3><div class="valor">{{ servidores_count }}</div></div><div class="card" style="border-left-color:#faa61a;"><h3>Comandos/Hora</h3><div class="valor">{{ "%.1f"|format(media_comandos) }}</div><p style="color:#b9bbbe;font-size:11px;margin:0;">Total: {{ qtd_comandos }}</p></div></div><div style="margin-top:20px;background:#2f3136;padding:20px;border-radius:8px;"><h2>🖥️ Servidores Conectados</h2>{% if nomes_servidores %}<ul class="server-list">{% for name in nomes_servidores %}<li>{{ name }}</li>{% endfor %}</ul>{% else %}<p>Nenhum servidor.</p>{% endif %}</div><a class="logout-btn" href="/logout">🚪 Sair</a></body></html>"""